local cJ={}
cJ.__index=cJ

function cJ.new(cI,cL)
    assert(cI,"Missing argument #1: targetValue")
    cL=cL or {}
    return setmetatable({
        _targetValue=cI,
        _velocity=cL.velocity or 1
    },cJ)
end

function cJ:step(F,gg)
    local R=F.value
    local pb=self._velocity
    local cF=self._targetValue
    local pc=gg*pb
    local p9=pc>=math.abs(cF-R)
    R=R+pc*(cF>R and 1 or -1)
    if p9 then
        R=self._targetValue
        pb=0
    end
    return {complete=p9,value=R,velocity=pb}
end

return cJ
